function chunkArray(data, chunkSize) {
  const results = [];
  for (let i = 0; i < data.length; i += chunkSize) {
    const chunk = data.slice(i, i + chunkSize);
    // 移除每个对象内的 "pairedItem"
    const processedChunk = chunk.map(item => item.json); // 直接提取json的内容
    results.push({
      details: processedChunk,
    });
  }
  return results;
}

